import type { StructureResolver } from 'sanity/structure';
import { singletonTypes, singletonDocIds } from './schemas';

/**
 * Custom desk structure for FICCC Sanity Studio.
 * - Singletons shown as single-doc editors at top (one per language)
 * - Document types shown as filterable lists below
 */
export const structure: StructureResolver = (S) =>
  S.list()
    .title('Content')
    .items([
      // --- Singletons ---
      S.listItem()
        .title('Settings & Navigation')
        .child(
          S.list()
            .title('Settings & Navigation')
            .items(
              singletonDocIds.map((singleton) =>
                S.listItem()
                  .title(singleton.title)
                  .id(singleton.id)
                  .child(
                    S.document()
                      .schemaType(singleton.type)
                      .documentId(singleton.id)
                      .title(singleton.title),
                  ),
              ),
            ),
        ),

      S.divider(),

      // --- Document types (excluding singletons) ---
      ...S.documentTypeListItems().filter(
        (item) => !singletonTypes.has(item.getId() as string),
      ),
    ]);

import { defineConfig } from 'sanity';
import { structureTool } from 'sanity/structure';
import { presentationTool } from 'sanity/presentation';
import { visionTool } from '@sanity/vision';
import { structure } from './sanity/structure';
import { schemaTypes } from './sanity/schemas';

// Use PUBLIC_ prefixed env vars so they're available in client-side bundles.
// In Astro, import.meta.env.PUBLIC_* are inlined at build time.
const projectId = import.meta.env.PUBLIC_SANITY_PROJECT_ID || 'placeholder';
const dataset = import.meta.env.PUBLIC_SANITY_DATASET || 'production';

export default defineConfig({
  name: 'ficcc',
  title: 'FICCC Website',
  projectId,
  dataset,
  plugins: [
    structureTool({ structure }),
    presentationTool({
      previewUrl: import.meta.env.PUBLIC_SANITY_PREVIEW_URL || 'http://localhost:4321',
    }),
    visionTool(),
  ],
  schema: {
    types: schemaTypes,
  },
});

import { defineType, defineField } from 'sanity';

export const sermon = defineType({
  name: 'sermon',
  title: 'Sermon',
  type: 'document',
  fields: [
    defineField({
      name: 'title',
      title: 'Title',
      type: 'string',
      validation: (rule) => rule.required(),
    }),
    defineField({
      name: 'slug',
      title: 'Slug',
      type: 'slug',
      options: { source: 'title' },
      validation: (rule) => rule.required(),
    }),
    defineField({
      name: 'speaker',
      title: 'Speaker',
      type: 'string',
    }),
    defineField({
      name: 'date',
      title: 'Date',
      type: 'date',
    }),
    defineField({
      name: 'series',
      title: 'Series',
      type: 'string',
    }),
    defineField({
      name: 'scripture',
      title: 'Scripture Reference',
      type: 'string',
    }),
    defineField({
      name: 'videoId',
      title: 'YouTube Video ID',
      type: 'string',
      description: 'YouTube video ID only (e.g. dQw4w9WgXcQ), not the full URL',
    }),
    defineField({
      name: 'language',
      title: 'Language',
      type: 'string',
      options: { list: ['en', 'zh'] },
      initialValue: 'en',
      validation: (rule) => rule.required(),
    }),
  ],
  orderings: [
    { title: 'Date (Newest)', name: 'dateDesc', by: [{ field: 'date', direction: 'desc' }] },
  ],
  preview: {
    select: { title: 'title', subtitle: 'speaker', language: 'language', date: 'date' },
    prepare: ({ title, subtitle, language, date }) => ({
      title: title || 'Untitled Sermon',
      subtitle: [subtitle, date, language?.toUpperCase()].filter(Boolean).join(' · '),
    }),
  },
});

